import { Separator as SeparatorPrimitive } from '@base-ui/react/separator';
import { forwardRef, type ComponentProps, type ComponentRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Separator.module.css';

const Separator = forwardRef<
  ComponentRef<typeof SeparatorPrimitive>,
  ComponentProps<typeof SeparatorPrimitive>
>(function Separator({ className, ...props }, ref) {
  return (
    <SeparatorPrimitive
      ref={ref}
      data-slot="separator-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

export { Separator };

@layer ui.components {
  .root {
    display: block;
    flex-shrink: 0;
    background-color: var(--separator-color, var(--color-border));

    &[data-orientation='horizontal'] {
      width: var(--separator-length-horizontal, 100%);
      height: var(--separator-thickness, 1px);
    }

    &[data-orientation='vertical'] {
      width: var(--separator-thickness, 1px);
      height: var(--separator-length-vertical, 1em);
    }
  }
}
